export function fetchData(url) {
  let status = 'pending';
  let result;
  const suspender = fetch(url)
    .then(res => res.json())
    .then(data => {
      status = 'success';
      result = data;
    })
    .catch(err => {
      status = 'error';
      result = err;
    });

  return {
    read() {
      if (status === 'pending') throw suspender;
      if (status === 'error') throw result;
      return result;
    },
  };
}
"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Теперь используем его в компоненте:"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"const resource = fetchData('/api/user');

function Profile() {
  const user = resource.read(); // ⚠️ бросает Promise, если данные ещё не готовы
  return <h1>{user.name}</h1>;
}

function App() {
  return (
    <Suspense fallback={<div>Загрузка профиля...</div>}>
      <Profile />
    </Suspense>
  );
}
"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"🔹 Что происходит:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"code"}],"text":"resource.read()"},{"type":"text","text":" бросает Promise → React “замораживает” рендер компонента "},{"type":"text","marks":[{"type":"code"}],"text":"Profile"},{"type":"text","text":";"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"React показывает "},{"type":"text","marks":[{"type":"code"}],"text":"fallback"},{"type":"text","text":" из "},{"type":"text","marks":[{"type":"code"}],"text":"Suspense"},{"type":"text","text":";"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Когда Promise завершается → React “возобновляет” рендер и вставляет "},{"type":"text","marks":[{"type":"code"}],"text":"Profile"},{"type":"text","text":" с данными."}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"⚙️ 4. Data Fetching в React Server Components (Next.js 13+)"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"В "},{"type":"text","marks":[{"type":"bold"}],"text":"React 18+"},{"type":"text","text":" и "},{"type":"text","marks":[{"type":"bold"}],"text":"Next.js 13/14"},{"type":"text","text":" Suspense интегрирован глубоко в серверный рендеринг."}]},{"type":"heading","attrs":{"textAlign":null,"level":3},"content":[{"type":"text","text":"Пример:"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"// app/page.js (Next.js 13+)
import { Suspense } from 'react';
import UserInfo from './UserInfo';
import UserPosts from './UserPosts';

