}
"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"🔹 Здесь React:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"отдаёт первую часть HTML (имя пользователя) сразу;"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"“приостанавливает” рендеринг "},{"type":"text","marks":[{"type":"code"}],"text":"UserPosts"},{"type":"text","text":", пока не получит данные;"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"позже "},{"type":"text","marks":[{"type":"bold"}],"text":"достримливает"},{"type":"text","text":" HTML для "},{"type":"text","marks":[{"type":"code"}],"text":"UserPosts"},{"type":"text","text":" (Streaming SSR);"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"всё происходит без перезагрузки страницы."}]}]}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"📘 Это работает благодаря новым API:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"code"}],"text":"renderToPipeableStream()"},{"type":"text","text":" — Node.js streaming SSR;"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"code"}],"text":"renderToReadableStream()"},{"type":"text","text":" — для Deno, Edge и т.д."}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"⚡ 5. Комбинация Suspense + React Query / SWR"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Пока React не имеет “встроенного” fetch-механизма,"},{"type":"hardBreak"},{"type":"text","text":"но популярные библиотеки уже добавили поддержку Suspense:"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"import { useQuery } from '@tanstack/react-query';
import { Suspense } from 'react';

function Todos() {
  const { data: todos } = useQuery({
    queryKey: ['todos'],
    queryFn: () => fetch('/api/todos').then(res => res.json()),
    suspense: true, // 👈 ключевая опция
  });

  return <ul>{todos.map(t => <li key={t.id}>{t.title}</li>)}</ul>;
}

export default function App() {
  return (
    <Suspense fallback={<div>Загрузка задач...</div>}>
      <Todos />
    </Suspense>
